mapper.select:
select id, user_id, game_type, level_num, source, updated_at
from user_progress
where user_id = #{userId}
  and game_type = #{gameType, jdbcType=INTEGER, typeHandler=com.sniper.game.wordgame.typehandler.GameTypeEnumTypeHandler}
limit 1

mapper.update:
update user_progress
set level_num = #{levelNum},
    updated_at = now()
where user_id = #{userId}
  and game_type = #{gameType, jdbcType=INTEGER, typeHandler=com.sniper.game.wordgame.typehandler.GameTypeEnumTypeHandler}

mapper.select:
SELECT COUNT(DISTINCT up.level_num)
FROM user_progress up
WHERE up.game_type = #{gameType, jdbcType=INTEGER, typeHandler=com.sniper.game.wordgame.typehandler.GameTypeEnumTypeHandler}
  AND up.level_num > #{levelNum}
